#include <bits/stdc++.h>
using namespace std;
int main(){
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    int n; cin >> n;
    vector<long long> a(n);
    for (auto &x : a) cin >> x;
    sort(a.begin(), a.end());
    int k = min(n, 3);
    for (int i = 0; i < k; i++) cout << a[i] << (i + 1 == k ? '\n' : ' ');
}
